Here are the public test cases for feature1_1_context_encode:
{
  "description": "Serialize a trace context (trace id, span id, parent id, one-byte flags) into its canonical colon-separated lowercase-hex wire string. Each of the three 64-bit ids is printed as unsigned lowercase hex and the flags byte as its unsigned hex value.",
  "cases": [
    {
      "input": {
        "op": "context_encode",
        "trace_id": -10,
        "span_id": -10,
        "parent_id": -10,
        "flags": 129
      },
      "expected_output": "context=fffffffffffffff6:fffffffffffffff6:fffffffffffffff6:81\n"
    },
    {
      "input": {
        "op": "context_encode",
        "trace_id": 255,
        "span_id": 221,
        "parent_id": 204,
        "flags": 4
      },
      "expected_output": "context=ff:dd:cc:4\n"
    }
  ]
}

Here are the public test cases for feature1_2_context_decode:
{
  "description": "Parse a colon-separated lowercase-hex trace-context wire string back into its four numeric components. The string must contain exactly four colon-separated hex fields; an empty string and a string with the wrong number of fields are reported as distinct normalized errors.",
  "cases": [
    {
      "input": {
        "op": "context_decode",
        "value": "ff:dd:cc:4"
      },
      "expected_output": "trace_id=255\nspan_id=221\nparent_id=204\nflags=4\n"
    },
    {
      "input": {
        "op": "context_decode",
        "value": "fffffffffffffff6:fffffffffffffff6:fffffffffffffff6:81"
      },
      "expected_output": "trace_id=-10\nspan_id=-10\nparent_id=-10\nflags=-127\n"
    },
    {
      "input": {
        "op": "context_decode",
        "value": "ff:ff:ff"
      },
      "expected_output": "error=malformed_tracer_state_string\nvalue=ff:ff:ff\n"
    },
    {
      "input": {
        "op": "context_decode",
        "value": ""
      },
      "expected_output": "error=empty_tracer_state_string\n"
    }
  ]
}

