Here are the public test cases for feature2_2_sampler_probabilistic:
{
  "description": "A probabilistic sampler samples a trace when its id falls within a boundary derived from the configured rate in [0,1]. Positive ids sample when id is at or below the positive boundary; negative ids sample when id is at or above the negative boundary. The reported tags carry type 'probabilistic' and the rate. A rate outside [0,1] is a normalized range error.",
  "cases": [
    {
      "input": {
        "op": "sampler_probabilistic",
        "rate": 0.5,
        "id": 4611686018427387903
      },
      "expected_output": "sampled=true\nsampler_type=probabilistic\nsampler_param=0.5\n"
    },
    {
      "input": {
        "op": "sampler_probabilistic",
        "rate": 0.5,
        "id": 4611686018427387905
      },
      "expected_output": "sampled=false\nsampler_type=probabilistic\nsampler_param=0.5\n"
    },
    {
      "input": {
        "op": "sampler_probabilistic",
        "rate": 0.5,
        "id": -4611686018427387904
      },
      "expected_output": "sampled=true\nsampler_type=probabilistic\nsampler_param=0.5\n"
    },
    {
      "input": {
        "op": "sampler_probabilistic",
        "rate": 0.5,
        "id": -4611686018427387905
      },
      "expected_output": "sampled=false\nsampler_type=probabilistic\nsampler_param=0.5\n"
    },
    {
      "input": {
        "op": "sampler_probabilistic",
        "rate": 0.1,
        "id": 20,
        "operation": "vadacurry"
      },
      "expected_output": "sampled=true\nsampler_type=probabilistic\nsampler_param=0.1\n"
    }
  ]
}

